#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int qp(int a,int b)
{
	int res=1;
	wh(b)
	{
		if(b&1)res=res*a;
		a=a*a;
		b>>=1;
	}
	return res;
}
const int m=1e6+5;
int n;
int a[m],f[m],l[30],res;
signed main()
{
	IOS
	cin>>n;
	FOR(i,1,n)
	{
		cin>>a[i];
	}
	FOR(i,1,n)
	{
		FOR(x,0,30)
		{
			if((a[i]&(1<<x))>0)
			{
				f[i]=max(f[i],f[l[x]]+1);//DP
				l[x]=i;
			}
		}
		res=max(res,f[i]);
	}
	cout<<res;
	return 0;
}
